GameData::Cutscene.define :ch49_hoopa_cameo do |scene|
  scene.play_bgm 'Pokemon HGSS - Goldenrod City'

  # TODO: Event Sequence - Parade Pause
  # - Mid-parade, a small purple ring opens above the crowd
